external_knowledge:
- "gardens where the bloom of planning is still fresh" refers to events with a status of 'Planned';
- "names and the seeds (emails) of the participants" refers to the names and emails of those participating in the event;
- "names and the initial sprout statuses of the teams" refers to the names and statuses of the teams participating;
- "fertile grounds that can accommodate more than a hundred souls" refers to events where the maximum number of participants is greater than 100.

sql:
SELECT events.event_name, race_classes.class_name
FROM events
JOIN race_classes ON events.event_id = race_classes.event_id;

SELECT COUNT(*) 
FROM participants
WHERE participant_id = 0;

SELECT team_name, team_status
FROM teams
WHERE event_id = 1;

SELECT event_name, COUNT(*) AS number_of_events 
FROM events 
WHERE location = 'Downtown Area';

SELECT name, team_name
FROM participants
WHERE event_id = 1 AND team_name IS NOT NULL;

SELECT COUNT(class_id) AS Total_Race_Classes
FROM race_classes
WHERE event_id = (SELECT event_id FROM events WHERE event_name = 'Sprint Triathlon');

SELECT p.name
FROM participants p
WHERE p.event_id = 1;
